import sys

def main(datasets_path,config_path,model_path=None):
    print('*'*66)

    config = load_config(config_path)
    project_path = './'
    # If research_area is not passed, use it from config
    research_area =  config.get('research_area')
    if not research_area:
        raise ValueError("Research area must be defined either in config or as an argument.")
    print(f"Research Area: {research_area}")
    print(f"Datasets Path: {datasets_path}")
    print(f'Config path :{config_path}')
    # datasets_path 一般是 ../datasets/exported_data
    print('*'*66)
    time.sleep(5)
    
    research_area_lower = research_area.lower()
    # 根据研究区域加载数据
    df_od_matrix, df_Origins, df_Destinations = load_training_data(research_area_lower, dataset_dir=datasets_path)
    
    # 将数据添加到配置对象中
    config['df_od_matrix'] = df_od_matrix
    config['df_Origins'] = df_Origins
    config['df_Destinations'] = df_Destinations
    print('rlsolver Print Config')
    print(config)

    action_space, observation_space = setup_environment(config)
    config['action_space'] = action_space
    config['observation_space'] = observation_space
    print("Action Space:", action_space)
    print("Observation Space:", observation_space)

    from envs.env_v3 import HospitalEnvironment_enhanced_v3
    # @title 训练并创建环境实例
    
    env = HospitalEnvironment_enhanced_v3(config)# 创建环境实例
    env = DummyVecEnv([lambda: env])# 包装环境


    # 如果提供了 model_path，则加载模型并跳过训练，否则训练模型
    if model_path:
        print(f"Loading model from {model_path} and skipping training...")
        time.sleep(5)
        from stable_baselines3 import PPO
        model = PPO.load(model_path)  # 加载模型
        

        
    else:
        print('Starting training model based on config file')
        time.sleep(5)
        from trainer.trainer import train_and_save_model
        model = train_and_save_model(env, config, project_path, research_area_lower)  # 训练并保存模型

    # 不管有没有 model path 总是要测试的 
    from trainer.tester import evaluate_model
    mean_reward, std_reward = evaluate_model(model,env)



import argparse
