    parser.add_argument('--model_path', type=str, help='Path to the pre-trained model. If provided, training will be skipped and this model will be used.')
    #  e.g.  python -m rlexperiment.rlsolver -d ./datasets/exported_data -c ./rlexperiment/configs/xiantao/config_xiantao.json --model_path ./rlexperiment/models/xiantao/2021-09-29_15-00-00.zip

    args = parser.parse_args()
